const ids = new Set<string>();
const built: QuizQuestionCandidateEntry[] = [];

for (let i = 0; i < raw.length; i++) {
  const q = raw[i];
  const id = `quiz-${String(i + 1).padStart(4, '0')}`;
  if (ids.has(id)) continue;
  ids.add(id);

  // shuffle choices deterministically but keep correctness mapping
  const originalChoices = q.choices.map((text, index) => ({ text, isCorrect: index === q.correctIndex }));
  // simple deterministic permutation based on question index
  const permuteBy = (i + 3) % 4;
  const permuted = [];
  for (let k = 0; k < 4; k++) {
    const src = (k + permuteBy) % 4;
    permuted.push(originalChoices[src]);
  }
  const choiceIds = ['A', 'B', 'C', 'D'];
  const finalChoices = permuted.map((c, idx) => ({ id: choiceIds[idx], text: c.text }));
  const correctChoice = permuted.find((c) => c.isCorrect);
  const correctChoiceId = correctChoice ? finalChoices.find((fc) => fc.text === correctChoice.text)!.id : 'A';

  built.push({
    id,
    prompt: q.prompt,
    choices: finalChoices,
    correctChoiceId,
    explanation: q.explanation,
    category: q.category,
    jlptLevel: JLPT,
    reviewStatus: REVIEW,
    connectedToApp: CONNECTED,
  });
}

export const quizQuestionCandidatePack: QuizQuestionCandidateEntry[] = built;
